-- Abstract aggiornato (22/22)
UPDATE archivio_items SET abstract = 'Riapre a Milano un circolo di estrema destra ''cuore nero'' e scoppiano tafferugli fra militanti antifascisti e forze dell''ordine, ci sono stati attimi di alta tensione. Insomma sembra di essere tornati indietro negli anni.' WHERE id_originale = 40260;
UPDATE archivio_items SET abstract = 'SUPER SENZA SCATTO - I tre naufraghi Aldo, Giovanni e Giacomo cercano di farsi notare da un aereo che sorvola la loro isola per reclamizzare l''offerta Wind, ma l''aereo non li nota. Il claim è "La tariffa senza scatto più conveniente d''Italia"..' WHERE id_originale = 40267;
UPDATE archivio_items SET abstract = 'Ha deciso di costituirsi parte civile la facoltà universitaria frequentata dalla giovane coppia che, a roma, era stata travolta e uccisa da un pirata della strada sul loro scooter. Il luogo dell''incidente è ormai diventato meta di pellegrinaggio da parte di parenti e curiosi..' WHERE id_originale = 40271;
UPDATE archivio_items SET abstract = 'DOPPIA RICARICA (AEREO)- Aldo Giovanni e Giacomo sono su un aereo guidato da zia Caterina che non ha il brevetto di volo: la donna ad un certo punto sviene, ma i tre non sanno comandare l''aereo che precipita..' WHERE id_originale = 40297;
UPDATE archivio_items SET abstract = 'OFFERTA CALCIO (INTER) - La Litizzetto annuncia che guarderà la partita dell''inter con Lippi sul suo videofonino e che dopo gli tirerà una testata. Il payoff è "Meglio cambiare, né!".' WHERE id_originale = 40307;
UPDATE archivio_items SET abstract = 'La scuola elementare è in subbuglio dopo le proposte di riforma della scuola elementare: fa discutere l''introduzione del maestro unico che, secondo molti insegnanti, verrebbe risucchiato dall''insegnamento di italiano e matematica a scapito delle discipline artistiche e motorie.' WHERE id_originale = 40335;
UPDATE archivio_items SET abstract = 'Bambini e rqagazzi si preparano per l''inizo della scuola il 15 settembre: si registra un incremento delle iscrizioni soprattutto alla scuola media e sono aumentati di quasi il 15% gli studenti stranieri nelle classi. Intanto per i ragazzi delle superiori continuano gli esami di riparazione.' WHERE id_originale = 40344;
UPDATE archivio_items SET abstract = 'In Veneto ha preso il via un progetto che coinvolge medici e carabinieri per prevenire le stragi del sabato sera. Le forze dall''ordine hanno intensificato i controlli riuscendo ad ottenere in tempo reale i risultati dei test alcolimetrici e antidroga sottoposti agli automobilisti. I risultati sono stati di 1 automobilista su 2 trovato positivo ad una delle due stostanze o ad entrambe.' WHERE id_originale = 40382;
UPDATE archivio_items SET abstract = 'ADSL E VOCE - La spot gioca su un''esclamazione di Greggio che, stressando il nome del brand, diventa un vero tormentone. Il testimonial arriva volando dalla finestra per aiutare una ragazza con le offerte di tiscali. Dopo aver fatto amicizia, Greggio fa per volare via ma si schianta in un televisore. Il costume e le movenze di Greggio sono ricalcate sull''immagine di Neo del film Matrix..' WHERE id_originale = 40401;
UPDATE archivio_items SET abstract = 'TANDEM FREE - Una coppia si confronta sulle proprie entrate economiche per poter aderire all''offerta Tiscali..' WHERE id_originale = 40402;
UPDATE archivio_items SET abstract = 'A partire dall''immagine di un cane che prende al volo un freesbee, tante scene di vita quotidiana, navigazione in Internet, foto, video compongono poco per volta il nuovo cellulare Balckberry. La voce over commenta: "Blackberry ti connette a tutto quello che ami nella vita". Claim: "Life on Blackberry"..' WHERE id_originale = 40436;
UPDATE archivio_items SET abstract = 'PRONTO PAGINE GIALLE - un gruppo di amici decide di andare in vacanza e incarica Bisio, uno di loro, di occuparsi della prenotazione. Lui chiama l''89.24.24 e si fa trovare dalla centralinista un albergo adatto. Il claim è "E'' più facile fare quello che vuoi con 89.24.24".' WHERE id_originale = 40439;
UPDATE archivio_items SET abstract = 'PRONTO PAGINE GIALLE (rugby) - Bisio e i suoi compagni di squadra hanno appena finito di giocare a rugby e hanno fame. Chiamano l'' 89.24.24 perché prenoti per loro una trattoria. Il claim è "E'' più facile fare quello che vuoi con 89.24.24".' WHERE id_originale = 40440;
UPDATE archivio_items SET abstract = 'INTERNET 7 MEGA - Abatantuono controlla che il figlio abbia svolto la ricerca su leopardi che doveva fare e il ragazzo spiega di averla fatta in pochissimo tempo grazie alla velocità di AliceADSL, cosa invece impossibile quando era giovane il padre. Musica : "Jingle originale" di Luis Bacalov. In chiusura il logo di Alice e di Telecom mentre la voce over esclama "Chiama il 187!"..' WHERE id_originale = 40445;
UPDATE archivio_items SET abstract = 'In Etiopia il riscatto dal sottosviluppo comincia sui banchi di scuola. Fra gli scolari più poveri di Addis Abeba c''è anche la cooperazione italiana che ha una parte importantissima nell''aiutare i bambini fra i poveri del mondo. Ci parla di questa ong la responsabile COOPI Barbara Russo.' WHERE id_originale = 40467;
UPDATE archivio_items SET abstract = 'A Lecce la guardia di finanza ha scoperto in un sotterraneo una vasta coltivazione ipertecnologica di marijuana; i controlli sono stati effettuati dopo che l''enel aveva ricevuto un'' ingente richiesta di energia elettrica che serviva per illuminare lo scantinato con lampade alogenee che sostituivano il sole.' WHERE id_originale = 40484;
UPDATE archivio_items SET abstract = 'A Roma le prime multe contro le prostitute che esercitano il loro lavoro in strada.  Molti cittadini però sono sciettici nei confronti di questo provvedimento perché suppongono che le prostitute si trasferiscano in case: non verrebbe perciò debellato il fenomeno.' WHERE id_originale = 40538;
UPDATE archivio_items SET abstract = '7 arresti per l''aggressione ad un ragazzo in una discoteca di Gela, colpevole solo di aver voluto accompagnare in discoteca l''ex ragazza del capo del gruppo di giovani. Sono stati individuati dal commissariato di Gela. Tra loro un minorenne, ora agli arresti domiciliari. Giovanni Martorana, la vittima 23enne, portterà per sempre sul viso e sul corpo i segni dell''aggressione subìta.' WHERE id_originale = 40633;
UPDATE archivio_items SET abstract = 'A Torino come in molte altre città universitarie, si è aperta la "Notte dei Ricercatori" un''inizaitiva che permette al grande pubblico di avvicinarsi e conoscere il lavoro che viene svolto in laboratorio. Molto attiava la partecipazione dei più piccoli.' WHERE id_originale = 40642;
UPDATE archivio_items SET abstract = 'AYGO SOUND - Un giovane carica due suoi amici a bordo della Toyota Aygo Sound. Ogni nuovo passeggero infila il proprio I-pod nell''apposita dock station integrata nel cruscotto, cambiando musica. Come recita la voce over, Toyota Aygo Sound è l''auto su cui la musica trova sempre posto..' WHERE id_originale = 40720;
UPDATE archivio_items SET abstract = 'SMART MHD - PALLONCINO - Una ragazza in attesa su un marciapiede osserva un giovane che facendo una bolla con il suo chewing gum riesce a creare una Smart. Lei cerca di imitarlo ma con scarsi risultati. I due sono vestiti alla moda, in un contesto urbano che potrebbe essere Milano o New York. Il brano musicale usato è "Kiko and the lavender moon" dei Los lobos..' WHERE id_originale = 40721;
UPDATE archivio_items SET abstract = 'CHEVROLET MATIZ - Una famiglia viaggia sulla propria Matiz. Le immagini vengono ritoccate da un programma che ricorda Photoshop illustrando le caratteristiche enunciate dalla voce over: capienza, consumi limitati, prezzo basso. In chiusura veniamo invitati a scegliere Matiz, così "tutto questo sarà reale". Compare il payoff "Get real"..' WHERE id_originale = 40723;
UPDATE archivio_items SET abstract = 'GO BEYOND - Un montaggio alternato sempre più serrato ci mostra immagini di uomini che, ognuno nella propria disciplina, sfidano i propri limiti: un esperto di arti marziali, un pianista, il guidatore di un auto a vela e - ovviamente - un uomo alla guida del Land Rover, lanciato su una tortuosa strada di montagna. Il payoff è conseguente: "Go beyond", ovvero "Vai oltre"..' WHERE id_originale = 40724;
UPDATE archivio_items SET abstract = 'Due immigrati in Umbria gestivano un traffico di esseri umani che venivano utilizzati per ila lavoro nero o per spaccio di droga in cambio di permessi di soggiorno falsi: la banda è stata scoperta dalla polizia grazie ad un infiltrato.' WHERE id_originale = 41353;
UPDATE archivio_items SET abstract = 'Avrebbe un movente razzista l''aggressione subìta a Roma da un uomo cinese. Vendetti Fernando, testimone dell''aggressione, racconta di un gruppo di giovani minorenni che ha affiancato l''uomo, ha urlato insulti razziali ed ha iniziato a picchiare sul volto il povero malcapitato. Ora è ricoverato all''ospedale con il setto nasale rotto. I minorenni sono stati fermati, sono 6.' WHERE id_originale = 41362;
UPDATE archivio_items SET abstract = 'NUOVA MAZDA SEI - PESCI - Su un fondale marino la nuova Mazda 6 si muove insieme a un branco di pesci, per poi fermarsi solitaria mentre la voce over ne annuncia l''uscita e il claim: "Independent way". Resta da verificare dove sta l''indipendenza di chi si muove all''interno di un branco. Il brano musicale è Platform Moon dei Jupiter one..' WHERE id_originale = 41372;
UPDATE archivio_items SET abstract = 'Si è tornati sui banchi di scuola anche nelle piccole scuole di montagna che riescono a vivere anche al contributo della Regione. Il TGR Piemonte ha deciso di andarne a vedere una nell''alto VCO. La cosa bella di questo paesino che consta di 60 abitanti è che tutti hanno dato una mano affinchè la scuola potesse funzionare. Attualmente sono 9 i bambini che frequentano questa piccolissima scuola..' WHERE id_originale = 41408;
UPDATE archivio_items SET abstract = 'Parte con oggi la campagna di Emergency: ''la nostra idea di pace è costruire un centro pediatrico nel sud del Darfur''. L''ormai mitici Gino Strada ci parla del progetto e di come intende farlo funzionare. Assistenza gratuita e di alta qualità verso i più deboli che sono i bambini da 0 a 14 anni l''idea che da anni accompagna ed è la filosofia di questa ONG..' WHERE id_originale = 41409;
UPDATE archivio_items SET abstract = 'Repertorio dell''orrore quello scoperto dalla Polizia durante un controllo contro la pedopornografia in Calabria. Immagini di bambini torturati, violentati e protagonisti di atti sessuali. 3 gli arrestati e molti i denunciati in diverse regioni italiane..' WHERE id_originale = 41412;
UPDATE archivio_items SET abstract = 'In migliaia hanno aderito oggi alla manifestazione promossa a Torino dalle associazioni dei genitori e dei sindacati contro la riforma della scuola voluta dal Ministro Gelmini. Grande partecipazione e nessun contrasto con le Forze dell''Ordine. Gli slogan non erano irriverenti, ma costruttivi d''altronde se si vuole dare un vero input alla scuola pubblica non servono tagli, ma investimenti..' WHERE id_originale = 41416;
UPDATE archivio_items SET abstract = 'Continuano le manifestazioni di protesta contro le forze dell''ordine a Palermo dopo la morte dei due diciassettenni investiti mentre ceercavano di scappare dalla polizia.' WHERE id_originale = 41465;
UPDATE archivio_items SET abstract = 'E'' in arrivo il teerzo film della serie "High school musical" e in America, alla prima del film, tantissime ragazzine in adorazione hanno accolto i loro idoli, primo fra tutti Zac Efron che sostiene che la serie piaccia perché i fans tentano di immedesimarsi nei personaggi.' WHERE id_originale = 41489;
UPDATE archivio_items SET abstract = 'MAI PROVATO PAVESINI? SKATE - Un uomo munito di speciali apparecchiature atterra su una pista da skateboard chiedendo a due ragazzi: "Mai provato Pavesini?". I due si guardano, prendono all''uomo la confezione di biscotti e poi, schiacciando un pulsante, lo rispediscono in aria..' WHERE id_originale = 41542;
UPDATE archivio_items SET abstract = 'Daria Bignardi intervista Eugenio Scalfari, giornalista e scrittore, direttore del quotidiano "La Repubblica". Scalfari si è sposato da pochi mesi a 84 anni di età: come lui spiega citando Pascal, "le vie del cuore sono diverse da quelle della ragione". Critiche a Cofferati: non doveva fare sia il padre che il sindaco. Si parla poi di Berlusconi, ex collega e avversario di Scalfari, e di economia. L''intervista prende poi una piega più intimista: Scalfari ricorda la sua infanzia, dai giochi agli anni del fascismo. Un consiglio alle donne: per essere più autorevoli devono accettare la loro età, amando le proprie rughe. Scalfari capisce davvero gli italiani? Alcuni lo accusano di essere lontano dal paese reale e di non fare amare l''Italia. Scalfari si difende: ritiene che in Italia manca una vera opinione pubblica e sente crescere di giorno in giorno la puzza del fascismo..' WHERE id_originale = 41618;
UPDATE archivio_items SET abstract = 'E per concludere si torna a Parigi con il corrispondente Fabio Cappelli che mostra vere e proprie esibizioni spettacolari messe in scena per le strade delle banlieau, dove è nato il parkour, oggi famoso in tutto il mondo. Ragazzi acrobati raccontano come sono riusciti a sfogare la rabbia dall’ emarginazione attraverso un percorso artistico, sfuggendo a tentazioni ben più compromettenti..' WHERE id_originale = 41663;
UPDATE archivio_items SET abstract = 'Un''altra giornata di protesta contro la riforma della scuola. La giornalista, un po’ di parte, dice che forse alcune proteste sono esagerate e non trovano neppure una spiegazione. Come se si protestasse tanto per protestare. Gelmini Maria Stella, intervistata dal Tg5, afferma l''importanza di fare scelte radicali, anche se impopolari, per dare veramente una svolta alla scuola italiana.' WHERE id_originale = 41674;
UPDATE archivio_items SET abstract = 'Questa volta le offese delle bulle sono finite sul web. Nella periferia di Milano una ragazzina di 13 anni ha scoperto che qualche compagna di scuola pubblicavano su internet un blog per insultarla. Distrutta dalla vergogna la ragazza è scappata di casa ma è stata ritrovata dai carabinieri. Per le responsabili sono state acccusate di molestie e bullismo.' WHERE id_originale = 41701;
UPDATE archivio_items SET abstract = 'A Milano gara di cocktail al femminile, si chiama "Lady drink", concorso e vetrina per le nuove tendenze nel mondo dei bar. Molti pensano che l''attività di preparazione dei cocktail sia prevalentemente maschile, ma molte donne lavorano in questo campo. Dai drink agli aperitivi con guarnizioni e decorazioni varie e creative, per soddisfare la clientela sempre più esigente..' WHERE id_originale = 41765;
UPDATE archivio_items SET abstract = 'Le telecamere ci mostrano i soccorsi dopo l''incidente del moldavo Ignazio, che a bordo di un furgone rubato ha travolto un''auto e ucciso un giovane di 19 anni. Sentiamo i commenti stupiti e arrabbiati della gente; il moldavo, sulla volante della polizia, non sfugge la telecamera, sembra sorridere beffardo..' WHERE id_originale = 41767;
UPDATE archivio_items SET abstract = 'Il servizio si apre con le immagini di controlli dei carabinieri che sottopongono gli automobilisti al test dell''etilometro. Un giovane risulta aver bevuto troppo e protesta. Un altro, alla guida di una Ferrari nera, è invece completamente sobrio..' WHERE id_originale = 41768;
UPDATE archivio_items SET abstract = 'Le varie facce del mondo del gambling: videopoker e lotterie di giorno, partite a carte nelle case private di notte. Racconto di una notte di poker Texas Hold''em tra giovani in Umbria. La partita si gioca tra amici, ma con soldi veri: a volte questo incrina i rapporti tra le persone. Alla fine il ragazzo vincitore racconta la sua vincita massima: 6000 euro. Le perdite, però, sono state altrettante..' WHERE id_originale = 41770;
UPDATE archivio_items SET abstract = 'Immagini in diretta dall''Università ''La Sapienza'' di Roma dove molti studenti si preparano ad una notte di occupazione e lotta contro i tagli voluti dalla Gelmini nei confronti della ricerca universitaria. Come una tegola arrivano le affermazioni del Presidente del Consiglio Silvio Berlusconi che vuole mandare le Forze dell''Ordine a togliere i picchetti affinchè, chi vuole studiare, lo possa fare. Veltroni, come Capo dell''Opposizione, si chiede se: in questo paese è ancora possibile dissentire ed esprimere opinioni diverse da chi governa, oppure no? In diretta dalla Facoltà di Fisica della Sapienza i giovani universitari, ma anche molti insegnanti, spiegano le ragioni dell''occupazione di 4 facoltà. Per concludere va in onda un servizio che fa vedere come gòli studenti stiano usando il web per tenersi in contatto e per mettere in atto forme di protesta comuni..' WHERE id_originale = 41775;
UPDATE archivio_items SET abstract = 'Presto uscirà un nuovissimo videogioco (Quantum of Solace) che tratta tutte le avventure del più popolare agente segreto: James Bond. Il videogioco è ambientato un po'' in tutto il mondo e i personaggi saranno davvero quasi uguali a quelli della rappresentazione cinematografica di 007 anche perché le voci dei personaggi saranno prestati dagli stessi doppiatori del film..' WHERE id_originale = 41795;
UPDATE archivio_items SET abstract = 'Il Governo ha proposto di dividere, in due classi differenti, i bambini italiani e quelli stranieri. Il GT, per vedere che questo intervento sia proprio necessario è andato in una scuola di Roma a vedere come convivono i bambini di varie nazionalità. In questa scuola multietnica i bambini si trovano molto bene insieme e la diversità di tradizione, di colore della pelle sembra quasi scomparsa..' WHERE id_originale = 41796;
UPDATE archivio_items SET abstract = 'Il GT oggi è andato per noi al Festival del Cinema di Roma. I ragazzi presenti hanno fatto un giro dietro le quinte e hanno visto il museo di topolino e hanno chiesto al disegnatore di disegnargli paperino. I ragazzi hanno anche votato il loro film preferito..' WHERE id_originale = 41799;
UPDATE archivio_items SET abstract = 'Il GT ha intervistato Jovanotti e gli ha chiesto che cosa ne pensa sulla nuova riforma, ha risposto che secondo lui la scuola avrebbe bisogno di più fondi mente invece il governo li sta togliendo..' WHERE id_originale = 41801;
UPDATE archivio_items SET abstract = 'Roberto Saviano è un giovane scrittore napoletano, autore del famoso libro sulla camorra, Gomorra, e da quel giorno è stato minacciato di morte proprio dalla camorra. Anche tanti ragazzi si sono appassionati alla sua storia affollando il suo blog e inviando tantissime richieste d''amicizia. Roberto però deve vivere sotto scorta, non può vedere i parenti e ha una difficilissima vita sociale..' WHERE id_originale = 41802;
UPDATE archivio_items SET abstract = 'Da oggi, Neri Marcorè ogni settimana ci proporrà un libro da leggere. Questa settimana ci consiglia "Come diventare esploratore" di Sir Henry Hardcastle. Questo libro ci insegna che studiare non è inutile anche per un esploratore perché quando incontra qualcosa lo deve saper riconoscere. Inoltre per diventare esploratori è necessario conoscere le lingue e i metodi di sopravvivenza..' WHERE id_originale = 41803;
UPDATE archivio_items SET abstract = 'Tutti sappiamo che è molto difficile cercare di attraversale, seppur sulle strisce pedonali, una strada trafficata. Quetsa mattina il Gt ci ha provato in una delle vie centrali di Roma, una di quelle che ogni mattina devono attraversare i bambini per raggiungere la scuola ed è capitato proprio un vero incidente tra due moto. Per fortuna nessune conseguenze..' WHERE id_originale = 41805;
UPDATE archivio_items SET abstract = 'La protesta della scula continua anche su internet, addirittura alcuni studenti hanno pensato di vendere l''università su internet. Alcuni ragazzi ci hanno accompagnatoa vedere alcuni siti trattanti l''argomento e abbiamo scoperto che ci sono molti video sulla riforma anche su You Tube..' WHERE id_originale = 41806;
UPDATE archivio_items SET abstract = '(Replica del 26/12/07) - La dispersione scolastica, il fenomeno che consiste nell’abbandono della scuola da parte dei ragazzi, é un problema che sta tornando d’attualità: non più, com’era un tempo, tra gli studenti italiani, bensì tra i figli degli immigrati. Difficoltà economiche e scarsa conoscenza della lingua li penalizzano, causando loro frequenti bocciature ed, appunto, abbandoni definitivi.  Così a Bologna la Fondazione del Monte é corsa ai ripari, avviando il progetto SeiPiù, che cerca di aiutare non solo i ragazzi ma anche le loro famiglie a poter usufruire effettivamente del bene dell’istruzione pubblica..' WHERE id_originale = 41810;
UPDATE archivio_items SET abstract = 'Una ragazza marocchina è stata picchiata sull''autobus a Varese perché si è seduta su un posto "non suo". La scrittrice marocchina Sumaya Abdel Quader intervistata ha detto che la violenza non è la soluzione per superare le paure nei confronti del diverso, ma bisogna usare tutte le energie per portare avanti un progetto comune per costruire una nuova Italia..' WHERE id_originale = 41811;
UPDATE archivio_items SET abstract = 'A Palermo un bambino di otto anni è obbligato dal nonno a vendere droga. Le immagini riprese dalle telecamere di sorveglianza mostrano che i traffici avvenivano in pieno giorno in un vicolo di Casteldarcia. La vendita avveniva dalla finestra del piano terra dell''abitazione cosicchè i ncompratori non dovevano neanche uscire dalle auto..' WHERE id_originale = 41815;
UPDATE archivio_items SET abstract = 'Ha iniziato a disegnare t-shirt a casa sua a New Yoek insieme ad amici ispirandosi al mondo dei graffiti, la sua grande passione. Si sta parlando di Mark Ecko lo stilista americano, affermato e apprezzato soprattutto dai giovani. Ha iniziato come writers e, per questo, non ama essere definito solo uno stilista; lui si sente un''artista a tutto tondo. (mah!)' WHERE id_originale = 41820;
UPDATE archivio_items SET abstract = 'La caduta dei capelli, dovuta agli ormoni della crescita, interessa i maschi ma anche le femmine. I capelli sono un''importante arma di seduzione tra i giovani, quindi fondamentale è intervenire subito: l''unica soluzione per stimolare la crescita dei capelli è l''uso di farmaci, prescritti da un dermatologo..' WHERE id_originale = 41844;
UPDATE archivio_items SET abstract = 'Info point per far conoscere la disattivazione e la messa in sicurezza dell''impianto nucleare di Saluggia. La Sogin, ditta che gestisce la decontaminazione del materiale nucleare di Saluggia ha creto un sito internet e un infopoint che è stato proposto alle scuole, molte le domande dei ragazzi per conoscere la procedura e il meccanismo dello smaltimento dei rifiuti nucleari..' WHERE id_originale = 41867;
UPDATE archivio_items SET abstract = '00CHRISTMAS CARD - Nello spot Ilary Blasi e Rino Gattuso sono indaffarati in varie attività: dalla preparazione degli addobbi di casa, ad un "maldestro confezionamento" di tortellini, alla lucidatura delle posate. Tutto in un clima allegro e festoso, quasi fiabesco. Musica: "Whistle while you work" colonna sonora di Biancaneve e i 7 nani. In chiusura il payoff "life is now"..' WHERE id_originale = 41890;
UPDATE archivio_items SET abstract = 'CASA (LUCCIOLE) - Scene di vita quotidiana immersa nella natura. Nello spot Francesco e Ilary interpretano se stessi in situazioni di vita quotidiana, ad esempio a letto prima di addormentarsi, mostrando tutta la loro ironia e spontaneità per rappresentare quell''idea di semplicità alla base della nuova offerta Vodafone. Musica: "Il cielo in una stanza" di Mina..' WHERE id_originale = 41894;
UPDATE archivio_items SET abstract = 'CASA (STELLA CADENTE) - Nello spot Francesco e Ilary interpretano se stessi in situazioni di vita quotidiana, ad esempio a letto prima di addormentarsi, mostrando tutta la loro ironia e spontaneità per rappresentare quell''idea di semplicità alla base della nuova offerta Vodafone. Musica: "Il cielo in una stanza" di Mina..' WHERE id_originale = 41895;
UPDATE archivio_items SET abstract = 'CONCORSO ORO - Due giovani scelgono di comprare una macchina e di pagarla con la vincita del concorso Oro della Tim. La voce over illustra le modalità di partecipazione e sul finale la testimonial esclama "Stavolta è mica un sogno!" mentre compare il logo con il payoff "vivere senza confini"..' WHERE id_originale = 41897;
UPDATE archivio_items SET abstract = 'CHRISTMAS CARD - Nello spot Ilary Blasi e Rino Gattuso sono indaffarati in varie attività: dalla preparazione degli addobbi di casa, ad un "maldestro confezionamento" di tortellini. Tutto in un clima allegro e festoso, quasi fiabesco. Musica: "Whistle while you work" colonna sonora di Biancaneve e i 7 nani. In chiusura Gattuso seduto a tavola per la cena esclama: "Christmas is…NOW"..' WHERE id_originale = 41898;
UPDATE archivio_items SET abstract = 'MAXXI TIM CASA - Nello spot il vigile Persichetti, condannato a morte, ricorre alla ''telefonata che allunga la vita'' per salvarsi dalla fucilazione. Il vigile si sveglierà poi in casa sua per accorgersi, come di consueto, che si è trattato di un sogno. Lo spot ricorda quello andato in onda anni fa interpretato dal comico Lopez..' WHERE id_originale = 41900;
UPDATE archivio_items SET abstract = 'TRIBU'' (ELEFANTE A FIORI) - La figlia del vigile Persichetti spiega ad un elefante colorato con fiori le offerte della tribù, ma è tutto soltanto un sogno della moglie di Urbano. Il vigile sostiene che il sogno con l''elefante a fiori sia dovuto ai peperoni mangiati a cena..' WHERE id_originale = 41904;
UPDATE archivio_items SET abstract = 'Ragazzi, genitori e insegnanti sono andati tutti a protestare contro la riforma appena approvata con palloncini e tanta musica. E'' successo a Roma, ma i partecipanti arrivavano da tutta Italia. Alcuni hanno passato anche la notte in treno pur di assistere a questa manifestazione..' WHERE id_originale = 41948;
UPDATE archivio_items SET abstract = 'I ragazzi di lecco, da qualche giorno stanno sperimentando una protesta contro la riforma Gelmini. Hanno fatto una prova con il maestro unico, ma i ragazzi non sembrano molto contenti..' WHERE id_originale = 41949;